    78→public class ConnectorsResource {
    79→    private static final Logger log = LoggerFactory.getLogger(ConnectorsResource.class);
    80→
    81→    private final Herder herder;
    82→    private final HerderRequestHandler requestHandler;
    83→    @jakarta.ws.rs.core.Context
