   138→    @POST
   139→    @Operation(summary = "Create a new connector")
   140→    public Response createConnector(final @Parameter(hidden = true) @QueryParam("forward") Boolean forward,
   141→                                    final @Context HttpHeaders headers,
   142→                                    final CreateConnectorRequest createRequest) throws Throwable {
   143→        // Trim leading and trailing whitespaces from the connector name, replace null with empty string
   144→        // if no name element present to keep validation within validator (NonEmptyStringWithoutControlChars
   145→        // allows null values)
   146→        String name = createRequest.name() == null ? "" : createRequest.name().trim();
   147→
   148→        Map<String, String> configs = createRequest.config();
   149→        checkAndPutConnectorConfigName(name, configs);
   150→
   151→        FutureCallback<Herder.Created<ConnectorInfo>> cb = new FutureCallback<>();
   152→        herder.putConnectorConfig(name, configs, createRequest.initialTargetState(), false, cb);
   153→        Herder.Created<ConnectorInfo> info = requestHandler.completeOrForwardRequest(cb, "/connectors", "POST", headers, createRequest,
   154→                new TypeReference<>() { }, new CreatedConnectorInfoTranslator(), forward);
   155→
   156→        URI location = UriBuilder.fromUri("/connectors").path(name).build();
   157→        return Response.created(location).entity(info.result()).build();
   158→    }
