   199→    @Operation(summary = "Reset the list of topics actively used by the specified connector")
   200→    public Response resetConnectorActiveTopics(final @PathParam("connector") String connector, final @Context HttpHeaders headers) {
   201→        if (isTopicTrackingDisabled) {
   202→            throw new ConnectRestException(Response.Status.FORBIDDEN.getStatusCode(),
