   213→    @PUT
   214→    @Path("/{connector}/config")
   215→    @Operation(summary = "Create or reconfigure the specified connector")
   216→    public Response putConnectorConfig(final @PathParam("connector") String connector,
   217→                                       final @Context HttpHeaders headers,
   218→                                       final @Parameter(hidden = true) @QueryParam("forward") Boolean forward,
   219→                                       final Map<String, String> connectorConfig) throws Throwable {
   220→        FutureCallback<Herder.Created<ConnectorInfo>> cb = new FutureCallback<>();
   221→        checkAndPutConnectorConfigName(connector, connectorConfig);
   222→
   223→        herder.putConnectorConfig(connector, connectorConfig, true, cb);
   224→        Herder.Created<ConnectorInfo> createdInfo = requestHandler.completeOrForwardRequest(cb, "/connectors/" + connector + "/config",
   225→                "PUT", headers, connectorConfig, new TypeReference<>() { }, new CreatedConnectorInfoTranslator(), forward);
   226→        Response.ResponseBuilder response;
   227→        if (createdInfo.created()) {
