   249→    @POST
   250→    @Path("/{connector}/restart")
   251→    @Operation(summary = "Restart the specified connector")
   252→    public Response restartConnector(final @PathParam("connector") String connector,
   253→                                 final @Context HttpHeaders headers,
   254→                                 final @DefaultValue("false") @QueryParam("includeTasks") @Parameter(description = "Whether to also restart tasks") Boolean includeTasks,
   255→                                 final @DefaultValue("false") @QueryParam("onlyFailed") @Parameter(description = "Whether to only restart failed tasks/connectors")Boolean onlyFailed,
   256→                                 final @Parameter(hidden = true) @QueryParam("forward") Boolean forward) throws Throwable {
   257→        RestartRequest restartRequest = new RestartRequest(connector, onlyFailed, includeTasks);
   258→        String forwardingPath = "/connectors/" + connector + "/restart";
   259→        if (restartRequest.forceRestartConnectorOnly()) {
   260→            // For backward compatibility, just restart the connector instance and return OK with no body
   261→            FutureCallback<Void> cb = new FutureCallback<>();
   262→            herder.restartConnector(connector, cb);
   263→            requestHandler.completeOrForwardRequest(cb, forwardingPath, "POST", headers, null, forward);
   264→            return Response.noContent().build();
   265→        }
   266→
   267→        // In all other cases, submit the async restart request and return connector state
   268→        FutureCallback<ConnectorStateInfo> cb = new FutureCallback<>();
   269→        herder.restartConnectorAndTasks(restartRequest, cb);
   270→        Map<String, String> queryParameters = new HashMap<>();
   271→        queryParameters.put("includeTasks", includeTasks.toString());
   272→        queryParameters.put("onlyFailed", onlyFailed.toString());
   273→        ConnectorStateInfo stateInfo = requestHandler.completeOrForwardRequest(cb, forwardingPath, "POST", headers, queryParameters, null, new TypeReference<>() {
   274→        }, new IdentityTranslator<>(), forward);
   275→        return Response.accepted().entity(stateInfo).build();
   276→    }
