   389→    // Check whether the connector name from the url matches the one (if there is one) provided in the connectorConfig
   390→    // object. Throw BadRequestException on mismatch, otherwise put connectorName in config
   391→    private void checkAndPutConnectorConfigName(String connectorName, Map<String, String> connectorConfig) {
   392→        String includedName = connectorConfig.get(ConnectorConfig.NAME_CONFIG);
   393→        if (includedName != null) {
   394→            if (!includedName.equals(connectorName))
   395→                throw new BadRequestException("Connector name configuration (" + includedName + ") doesn't match connector name in the URL (" + connectorName + ")");
   396→        } else {
   397→            connectorConfig.put(ConnectorConfig.NAME_CONFIG, connectorName);
   398→        }
   399→    }
